import { KernelFunction } from '@microsoft/semantic-kernel';

const PII_REGEX = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b|\b\d{3}-\d{2}-\d{4}\b/g;

function piiInterceptor(plugin: KernelFunction) {
  return async (...args: any[]) => {
    const result = await plugin(...args);

    const piiMatches = result.match(PII_REGEX);
    if (piiMatches) {
      console.warn('PII detected in plugin output:', {
        plugin: plugin.name,
        pii: piiMatches,
        result
      });
      throw new Error(`PII leak detected in ${plugin.name}`);
    }

    return result;
  };
}

// Wrap contact plugin
const safeContactPlugin = piiInterceptor(contactPlugin);
