import { HandlebarsPlanner } from '@microsoft/semantic-kernel-planner-handlebars';
import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: 'your-vex-key' });

class SafePlanner extends HandlebarsPlanner {
  async createPlan(goal: string): Promise<Plan> {
    const plan = await super.createPlan(goal);

    // Sanitize all plan steps
    for (const step of plan.steps) {
      if (step.functionCall) {
        const sanitizedArgs = await vex.sanitizePii(step.functionCall.arguments);
        step.functionCall.arguments = sanitizedArgs;
      }
    }

    return plan;
  }
}

const safePlanner = new SafePlanner(kernel);
